module pipeline_processor (  
    input [3:0] A,  
    input [3:0] B,  
    input op,  
    input clk,  
    output reg [3:0] result  
);  
    reg [3:0] misleading_stage1_result;  
    always @(posedge clk) begin  
        if (op == 0) begin  
            misleading_stage1_result <= A + B;  
        end else begin  
            misleading_stage1_result <= A - B;  
        end  
    end  

    always @(posedge clk) begin  
        result <= misleading_stage1_result;  
    end  
endmodule
